<template>
  <section>
    <!-- ================= Legends ================= -->
    <div class="row">
      <div class="col-12 mb-2">
        <div class="mr-2 d-inline-block">
          <span class="legend-pending colorboxsquare"></span>
          Modified Record
        </div>
        <div class="mr-2 d-inline-block">
          <span class="legend-Progress colorboxsquare"></span>
          New Record
        </div>
      </div>
    </div>

    <div class="row">
      <!-- ================= LEFT : CURRENT / SELECTED VERSION ================= -->
      <div class="col-6">
        <div class="col-12 mb-2 p-0">
          <div class="heading-border">
            <h5 class="h5">
              <span>{{ currentLabel }}</span>
            </h5>
          </div>
        </div>

        <div class="col-lg-12 mb-2 p-0 listing">
          <div class="table-responsive">
            <table class="table table-bordered">
              <thead>
                <tr>
                  <th>{{ $t('LimitFor') }}</th>
                  <th>{{ $t('WorkCode') }}</th>
                  <th>{{ $t('LimitValue') }}</th>
                  <th>{{ $t('DayLimit') }}</th>
                  <th>{{ $t('AlternateWorkCode') }}</th>
                  <th>{{ $t('IsApplicableToAll') }}</th>
                  <th>{{ $t('Count') }}</th>
                  <th>{{ $t('DisplayOrder') }}</th>
                  <th>{{ $t('Status') }}</th>
                </tr>
              </thead>
              <tbody>
                <tr
                  v-for="(item, idx) in currentLimitData"
                  v-if="currentLimitData && currentLimitData.length"
                  :key="'cur-' + idx"
                >
                  <td>{{ item.CLINETLIMTNAME }}</td>
                  <td>{{ item.WORK_CODE }}</td>
                  <td>{{ item.LIMIT }}</td>
                  <td>{{ item.LIMIT_DAYS }}</td>
                  <td>{{ item.ALTERNATE_WORK_CODE }}</td>
                  <td>{{ item.IS_APPLICABLE_TO_ALL ? 'Yes' : 'No' }}</td>
                  <td>{{ item.UTILITY_COUNT }}</td>
                  <td>{{ item.DISPLAY_ORDER }}</td>
                  <td>
                    {{ item.STATUS_ID === 1001 ? $t('Active') : $t('Deleted') }}
                  </td>
                </tr>

                <tr v-if="!currentLimitData || !currentLimitData.length">
                  <td class="text-center text-danger no-record" colspan="9">
                    {{ $t('NoRecordfound') }}
                  </td>
                </tr>
              </tbody>
            </table>
          </div>
        </div>
      </div>

      <!-- ================= RIGHT : PREVIOUS VERSION ================= -->
      <div class="col-6">
        <div class="col-12 mb-2 p-0">
          <div class="heading-border">
            <h5 class="h5">
              <span v-if="previousLabel">
                {{ previousLabel }}
              </span>
              <span v-else class="text-muted">
                Version Number :
              </span>
            </h5>
          </div>
        </div>

        <div class="col-lg-12 mb-2 p-0 listing">
          <div class="table-responsive">
            <table class="table table-bordered">
              <thead>
                <tr>
                  <th>{{ $t('LimitFor') }}</th>
                  <th>{{ $t('WorkCode') }}</th>
                  <th>{{ $t('LimitValue') }}</th>
                  <th>{{ $t('DayLimit') }}</th>
                  <th>{{ $t('AlternateWorkCode') }}</th>
                  <th>{{ $t('IsApplicableToAll') }}</th>
                  <th>{{ $t('Count') }}</th>
                  <th>{{ $t('DisplayOrder') }}</th>
                  <th>{{ $t('Status') }}</th>
                </tr>
              </thead>
              <tbody>
              <tr
  v-for="(item, idx) in previousLimitData"
  :key="'prev-' + idx"
  v-if="item.RULE_VERSION !== null"
>
  <td>{{ item.CLINETLIMTNAME }}</td>
  <td>{{ item.WORK_CODE }}</td>
  <td>{{ item.LIMIT }}</td>
  <td>{{ item.LIMIT_DAYS }}</td>
  <td>{{ item.ALTERNATE_WORK_CODE }}</td>
  <td>{{ item.IS_APPLICABLE_TO_ALL ? 'Yes' : 'No' }}</td>
  <td>{{ item.UTILITY_COUNT }}</td>
  <td>{{ item.DISPLAY_ORDER }}</td>
  <td>{{ item.Status === '1001' ? $t('Active') : $t('Deleted') }}</td>
</tr>

<tr v-if="!previousLimitData || previousLimitData.every(item => item.RULE_VERSION === null)">
  <td class="text-center text-danger no-record" colspan="9">
    {{ $t('NoRecordfound') }}
  </td>
</tr>

              </tbody>
            </table>
          </div>
        </div>
      </div>
    </div>
  </section>
</template>

<script>
export default {
  name: "LimitHistory",
  props: {
    currentLimitData: {
      type: Array,
      default: () => []
    },
    previousLimitData: {
      type: Array,
      default: () => []
    },
    currentVersion: {
      type: Number,
      required: true
    },
    previousVersion: {
      type: Number,
      default: null
    },
    latestVersion: {
      type: Number,
      required: true
    }
  },
  computed: {
    isLatestSelected() {
      return this.currentVersion === this.latestVersion;
    },
    currentLabel() {
      return this.isLatestSelected
        ? this.$t('CurrentVersion')
        : `Version Number : ${this.currentVersion}`;
    },
    previousLabel() {
      return this.previousVersion
        ? `Version Number : ${this.previousVersion}`
        : null;
    }
  }
};
</script>

<style scoped>
.no-record {
  font-size: 13px;
}
</style>
